import React, { useState } from 'react';
import { LayoutGrid, User, Lock, ArrowRight } from 'lucide-react';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Logic: If username contains 'admin', they get faculty access
    const isAdmin = username.toLowerCase().includes('admin');
    
    const userData = { 
      name: username, 
      id: "NIMIT-" + Math.floor(Math.random() * 1000),
      isAdmin: isAdmin 
    };

    localStorage.setItem('user_info', JSON.stringify(userData));
    onLogin(userData);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center p-6 relative overflow-hidden font-sans">
      
      {/* 🌌 High-End Background Effects */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 blur-[120px] rounded-full"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full"></div>

      <div className="w-full max-w-md bg-white/5 backdrop-blur-2xl border border-white/10 p-10 rounded-[2.5rem] shadow-[0_0_50px_rgba(0,0,0,0.5)] relative z-10 animate-fadeIn">
        
        {/* Logo Section */}
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-tr from-indigo-500 to-purple-500 shadow-lg mb-6">
            <LayoutGrid className="w-8 h-8 text-white" />
          </div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight mb-2">CampusCanvas</h2>
          <p className="text-gray-400 text-sm tracking-wide">NIMIT PROJECT REPOSITORY</p>
        </div>

        {/* 🛠️ Main Form Structure */}
        <form onSubmit={handleSubmit} className="space-y-6">
          
          {/* Username Field */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Username</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <User className="h-5 w-5 text-gray-500 group-focus-within:text-indigo-400 transition-colors" />
              </div>
              <input 
                type="text" 
                required 
                value={username} 
                onChange={(e) => setUsername(e.target.value)} 
                className="w-full bg-black/40 border border-white/10 rounded-xl pl-11 pr-4 py-4 text-white placeholder-gray-700 outline-none focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/50 transition-all duration-300" 
                placeholder="Enter your username" 
              />
            </div>
          </div>

          {/* Password Field */}
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 ml-1">Password</label>
            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Lock className="h-5 w-5 text-gray-500 group-focus-within:text-purple-400 transition-colors" />
              </div>
              <input 
                type="password" 
                required 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="w-full bg-black/40 border border-white/10 rounded-xl pl-11 pr-4 py-4 text-white placeholder-gray-700 outline-none focus:border-purple-500/50 focus:ring-1 focus:ring-purple-500/50 transition-all duration-300" 
                placeholder="••••••••" 
              />
            </div>
          </div>

          {/* Submit Button */}
          <button 
            type="submit" 
            className="w-full bg-white text-black font-black rounded-xl py-4 flex items-center justify-center gap-2 hover:bg-indigo-50 hover:shadow-[0_0_20px_rgba(255,255,255,0.2)] transition-all active:scale-[0.98] mt-8 group"
          >
            LOGIN TO SYSTEM
            <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
          </button>
        </form>
        
        <div className="mt-10 pt-6 border-t border-white/5 text-center">
          <p className="text-[10px] text-gray-600 font-bold uppercase tracking-[0.2em]">
            Institutional Archive Access Only
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
